BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Shock Management' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Shock Management', 'Shock types, recognition, and targeted treatment', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - Shock Management (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Shock Management - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Shock definition in this shock scenario?', 'Which finding best supports Shock definition in this shock scenario?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "Shock is inadequate tissue perfusion causing insufficient oxygen delivery and cellular dysfunction."}, {"id": "c", "text": "This pattern is more consistent with Septic profile."}, {"id": "d", "text": "Shock has no effect on oxygen delivery in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Shock is inadequate tissue perfusion causing insufficient oxygen delivery and cellular dysfunction. Treat perfusion failure early to prevent irreversible organ injury.', 'Shock Management - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews hemodynamic data. Which interpretation best matches Shock metabolic pathway?', 'The nurse reviews hemodynamic data. Which interpretation best matches Shock metabolic pathway?', '[{"id": "a", "text": "Track lactate and organ function to detect decompensation early."}, {"id": "b", "text": "Shock cannot cause organ dysfunction in this note."}, {"id": "c", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "d", "text": "Blood pressure normalization alone confirms full recovery."}]'::jsonb, '["a"]'::jsonb, 'Correct because In shock, anaerobic metabolism develops with lactic acidosis and can progress to MODS. Track lactate and organ function to detect decompensation early.', 'Shock Management - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Hypovolemic profile?', 'Which clinical judgment is most accurate regarding Hypovolemic profile?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "Hypovolemic shock has high CO and low SVR in this note."}, {"id": "c", "text": "This pattern is more consistent with Obstructive profile."}, {"id": "d", "text": "Hypovolemic shock stems from blood/fluid loss with low CO, high SVR, flat neck veins, pallor, and tachycardia."}]'::jsonb, '["d"]'::jsonb, 'Correct because Hypovolemic shock stems from blood/fluid loss with low CO, high SVR, flat neck veins, pallor, and tachycardia. Rapid volume replacement and bleeding control are primary priorities.', 'Shock Management - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Cardiogenic profile?', 'In urgent triage, which conclusion aligns with Cardiogenic profile?', '[{"id": "a", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "b", "text": "Cardiogenic shock has elevated CO in this note."}, {"id": "c", "text": "Support contractility and address the primary cardiac lesion urgently."}, {"id": "d", "text": "This pattern is more consistent with Early shock signs."}]'::jsonb, '["c"]'::jsonb, 'Correct because Cardiogenic shock is pump failure (e.g., MI/HF/cardiomyopathy) with low CO, high SVR, JVD, crackles, S3, and frothy sputum. Support contractility and address the primary cardiac lesion urgently.', 'Shock Management - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Septic profile?', 'Which statement most appropriately reflects Septic profile?', '[{"id": "a", "text": "Septic shock always has high SVR in this note."}, {"id": "b", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "c", "text": "Septic shock is distributive vasodilation with low SVR and warm flushed skin early; CO may be high early then low late."}, {"id": "d", "text": "This pattern is more consistent with Late shock signs."}]'::jsonb, '["c"]'::jsonb, 'Correct because Septic shock is distributive vasodilation with low SVR and warm flushed skin early; CO may be high early then low late. Initiate sepsis bundle quickly before transition to late hypodynamic phase.', 'Shock Management - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Neurogenic profile in this shock scenario?', 'Which finding best supports Neurogenic profile in this shock scenario?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "This pattern is more consistent with NCLEX early warning."}, {"id": "c", "text": "Recognize bradycardia-hypotension pattern as distinguishing feature."}, {"id": "d", "text": "Blood pressure normalization alone confirms full recovery."}]'::jsonb, '["c"]'::jsonb, 'Correct because Neurogenic shock follows spinal injury with loss of sympathetic tone causing low CO, low SVR, bradycardia, hypotension, and warm dry skin below injury. Recognize bradycardia-hypotension pattern as distinguishing feature.', 'Shock Management - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews hemodynamic data. Which interpretation best matches Obstructive profile?', 'The nurse reviews hemodynamic data. Which interpretation best matches Obstructive profile?', '[{"id": "a", "text": "Obstructive shock is caused by volume loss only in this note."}, {"id": "b", "text": "This pattern is more consistent with General initial treatment."}, {"id": "c", "text": "Obstructive shock has high CO in this note."}, {"id": "d", "text": "Obstructive shock is due to physical flow obstruction (tamponade, tension PTX, PE) with low CO and high SVR."}]'::jsonb, '["d"]'::jsonb, 'Correct because Obstructive shock is due to physical flow obstruction (tamponade, tension PTX, PE) with low CO and high SVR. Definitive relief of obstruction is mandatory for recovery.', 'Shock Management - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Early shock signs?', 'Which clinical judgment is most accurate regarding Early shock signs?', '[{"id": "a", "text": "Hypotension is first sign of shock in this note."}, {"id": "b", "text": "Normal BP excludes early shock in this note."}, {"id": "c", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "d", "text": "Do not be reassured by normal BP when compensatory signs are present."}]'::jsonb, '["d"]'::jsonb, 'Correct because Early compensated shock shows tachycardia first, possible normal BP, cool clammy skin, tachypnea, anxiety, and slight urine decrease. Do not be reassured by normal BP when compensatory signs are present.', 'Shock Management - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Late shock signs?', 'In urgent triage, which conclusion aligns with Late shock signs?', '[{"id": "a", "text": "Late decompensated shock includes hypotension, altered LOC, urine output <30 mL/hr, mottled/cyanotic skin, lactic acidosis, and MODS progression."}, {"id": "b", "text": "Late shock preserves normal mentation in this note."}, {"id": "c", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "d", "text": "Late shock has improving urine output in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Late decompensated shock includes hypotension, altered LOC, urine output <30 mL/hr, mottled/cyanotic skin, lactic acidosis, and MODS progression. Escalate aggressively at decompensation to prevent arrest.', 'Shock Management - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects NCLEX early warning?', 'Which statement most appropriately reflects NCLEX early warning?', '[{"id": "a", "text": "Normal BP definitively excludes shock in this note."}, {"id": "b", "text": "This pattern is more consistent with Severe shock invasive monitoring."}, {"id": "c", "text": "Prioritize trend recognition over single BP value."}, {"id": "d", "text": "Bradycardia is first universal shock sign in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because NCLEX priority notes that tachycardia is first and BP drops last, so normal BP does not rule out shock. Prioritize trend recognition over single BP value.', 'Shock Management - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports General initial treatment in this shock scenario?', 'Which finding best supports General initial treatment in this shock scenario?', '[{"id": "a", "text": "Monitoring can be delayed until subtype confirmed in this note."}, {"id": "b", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "c", "text": "General treatment includes oxygenation, large-bore IV access, continuous monitoring, urine output goals, and broad shock labs."}, {"id": "d", "text": "This pattern is more consistent with Shock lab panel."}]'::jsonb, '["c"]'::jsonb, 'Correct because General treatment includes oxygenation, large-bore IV access, continuous monitoring, urine output goals, and broad shock labs. Rapid stabilization and monitoring should start before definitive subtype treatment.', 'Shock Management - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews hemodynamic data. Which interpretation best matches Positioning rule?', 'The nurse reviews hemodynamic data. Which interpretation best matches Positioning rule?', '[{"id": "a", "text": "Cardiogenic shock requires leg elevation above heart in this note."}, {"id": "b", "text": "Choose position by shock type to avoid worsening pulmonary congestion."}, {"id": "c", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "d", "text": "This pattern is more consistent with Hypovolemic treatment specifics."}]'::jsonb, '["b"]'::jsonb, 'Correct because Shock positioning is generally supine with legs elevated (Trendelenburg/modified), except cardiogenic shock where HOB is elevated. Choose position by shock type to avoid worsening pulmonary congestion.', 'Shock Management - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Urine output target?', 'Which clinical judgment is most accurate regarding Urine output target?', '[{"id": "a", "text": "This pattern is more consistent with Cardiogenic treatment specifics."}, {"id": "b", "text": "Goal urine output is 0.05 mL/kg/hr in this note."}, {"id": "c", "text": "Foley monitoring goal is urine output greater than 0.5 mL/kg/hr."}, {"id": "d", "text": "Shock subtype is irrelevant once oxygen is started."}]'::jsonb, '["c"]'::jsonb, 'Correct because Foley monitoring goal is urine output greater than 0.5 mL/kg/hr. Renal perfusion tracking is critical in shock resuscitation.', 'Shock Management - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Severe shock invasive monitoring?', 'In urgent triage, which conclusion aligns with Severe shock invasive monitoring?', '[{"id": "a", "text": "Only pulse oximetry is needed in severe shock in this note."}, {"id": "b", "text": "This pattern is more consistent with Septic bundle timing."}, {"id": "c", "text": "Use invasive monitoring when rapid titration is needed."}, {"id": "d", "text": "Invasive lines are contraindicated in severe shock in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Arterial and central lines are used in severe shock for close hemodynamic management. Use invasive monitoring when rapid titration is needed.', 'Shock Management - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Shock lab panel?', 'Which statement most appropriately reflects Shock lab panel?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "No labs are needed during shock in this note."}, {"id": "c", "text": "This pattern is more consistent with Septic vasopressors/steroids."}, {"id": "d", "text": "Recommended labs include ABG, lactate, CBC, BMP, coagulation tests, and blood cultures in sepsis."}]'::jsonb, '["d"]'::jsonb, 'Correct because Recommended labs include ABG, lactate, CBC, BMP, coagulation tests, and blood cultures in sepsis. Combine perfusion, metabolic, and infectious data quickly.', 'Shock Management - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Hypovolemic treatment specifics in this shock scenario?', 'Which finding best supports Hypovolemic treatment specifics in this shock scenario?', '[{"id": "a", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "b", "text": "Vasopressors are first-line before fluids in hypovolemia in this note."}, {"id": "c", "text": "Bleeding source control is unnecessary in this note."}, {"id": "d", "text": "Restore intravascular volume before vasoconstriction strategies."}]'::jsonb, '["d"]'::jsonb, 'Correct because Hypovolemic treatment is IV crystalloids (NS/LR), blood products if hemorrhagic, bleeding control, and delaying vasopressors until volume replacement. Restore intravascular volume before vasoconstriction strategies.', 'Shock Management - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews hemodynamic data. Which interpretation best matches Cardiogenic treatment specifics?', 'The nurse reviews hemodynamic data. Which interpretation best matches Cardiogenic treatment specifics?', '[{"id": "a", "text": "Inotropes are contraindicated in cardiogenic shock in this note."}, {"id": "b", "text": "Cardiogenic management includes treating cause (e.g., PCI for MI), inotropes (dobutamine/milrinone), norepinephrine if persistent hypotension, diuretics if overloaded, and possible IABP/LVAD."}, {"id": "c", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "d", "text": "This pattern is more consistent with Obstructive definitive care."}]'::jsonb, '["b"]'::jsonb, 'Correct because Cardiogenic management includes treating cause (e.g., PCI for MI), inotropes (dobutamine/milrinone), norepinephrine if persistent hypotension, diuretics if overloaded, and possible IABP/LVAD. Support pump function while correcting primary cardiac pathology.', 'Shock Management - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Septic bundle timing?', 'Which clinical judgment is most accurate regarding Septic bundle timing?', '[{"id": "a", "text": "Antibiotics are delayed until cultures finalize in this note."}, {"id": "b", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "c", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "d", "text": "Time-sensitive sepsis actions strongly influence outcomes."}]'::jsonb, '["d"]'::jsonb, 'Correct because Septic shock care includes blood cultures before antibiotics, broad-spectrum antibiotics within 1 hour, and 30 mL/kg fluid bolus within 3 hours. Time-sensitive sepsis actions strongly influence outcomes.', 'Shock Management - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Septic vasopressors/steroids?', 'In urgent triage, which conclusion aligns with Septic vasopressors/steroids?', '[{"id": "a", "text": "Steroids are always first treatment before fluids in this note."}, {"id": "b", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "c", "text": "Norepinephrine is first-line vasopressor in septic shock, with corticosteroids considered if refractory."}, {"id": "d", "text": "This pattern is more consistent with Dobutamine profile."}]'::jsonb, '["c"]'::jsonb, 'Correct because Norepinephrine is first-line vasopressor in septic shock, with corticosteroids considered if refractory. Escalate pressor support and adjuncts when fluid response is inadequate.', 'Shock Management - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Neurogenic treatment specifics?', 'Which statement most appropriately reflects Neurogenic treatment specifics?', '[{"id": "a", "text": "This pattern is more consistent with Epinephrine and vasopressin profiles."}, {"id": "b", "text": "Address vasodilation and bradycardia while protecting spinal injury."}, {"id": "c", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "d", "text": "Blood pressure normalization alone confirms full recovery."}]'::jsonb, '["b"]'::jsonb, 'Correct because Neurogenic shock treatment includes cautious fluids, norepinephrine/phenylephrine, atropine for bradycardia, and spinal immobilization. Address vasodilation and bradycardia while protecting spinal injury.', 'Shock Management - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Obstructive definitive care in this shock scenario?', 'Which finding best supports Obstructive definitive care in this shock scenario?', '[{"id": "a", "text": "Pericardiocentesis is contraindicated in tamponade in this note."}, {"id": "b", "text": "This pattern is more consistent with Shock-type mnemonic."}, {"id": "c", "text": "Obstructive shock is corrected by fluids alone in this note."}, {"id": "d", "text": "Obstructive shock requires removing obstruction: pericardiocentesis for tamponade, needle decompression for tension PTX, and thrombolysis/embolectomy for PE."}]'::jsonb, '["d"]'::jsonb, 'Correct because Obstructive shock requires removing obstruction: pericardiocentesis for tamponade, needle decompression for tension PTX, and thrombolysis/embolectomy for PE. Definitive mechanical relief is essential; supportive measures alone are insufficient.', 'Shock Management - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews hemodynamic data. Which interpretation best matches Norepinephrine profile?', 'The nurse reviews hemodynamic data. Which interpretation best matches Norepinephrine profile?', '[{"id": "a", "text": "Monitor peripheral perfusion while titrating SVR support."}, {"id": "b", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "c", "text": "Norepinephrine lowers SVR in this note."}, {"id": "d", "text": "Norepinephrine is pure β2 bronchodilator in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Norepinephrine acts via α1 + β1 to increase SVR with mild CO effect and is first-line for septic shock; also used in neurogenic shock. Monitor peripheral perfusion while titrating SVR support.', 'Shock Management - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Dobutamine profile?', 'Which clinical judgment is most accurate regarding Dobutamine profile?', '[{"id": "a", "text": "Dobutamine is a β1 inotrope increasing contractility and is used in cardiogenic shock with reduced EF."}, {"id": "b", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "c", "text": "This pattern is more consistent with Shock definition."}, {"id": "d", "text": "Dobutamine primarily decreases contractility in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Dobutamine is a β1 inotrope increasing contractility and is used in cardiogenic shock with reduced EF. Use inotropy to augment forward flow in pump failure.', 'Shock Management - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Epinephrine and vasopressin profiles?', 'In urgent triage, which conclusion aligns with Epinephrine and vasopressin profiles?', '[{"id": "a", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "b", "text": "This pattern is more consistent with Shock metabolic pathway."}, {"id": "c", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "d", "text": "Match pressor receptor profile to clinical indication."}]'::jsonb, '["d"]'::jsonb, 'Correct because Epinephrine is α1/β1/β2 and used in anaphylaxis/cardiac arrest, while vasopressin (V1) is septic add-on vasoconstrictor. Match pressor receptor profile to clinical indication.', 'Shock Management - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Shock-type mnemonic?', 'Which statement most appropriately reflects Shock-type mnemonic?', '[{"id": "a", "text": "Distributive is blocked exit in this note."}, {"id": "b", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "c", "text": "Cardiogenic is leaky pipes in this note."}, {"id": "d", "text": "Mnemonic in note: H hypovolemic (empty tank), C cardiogenic (broken pump), D distributive (leaky pipes), O obstructive (blocked exit)."}]'::jsonb, '["d"]'::jsonb, 'Correct because Mnemonic in note: H hypovolemic (empty tank), C cardiogenic (broken pump), D distributive (leaky pipes), O obstructive (blocked exit). Use simple mechanistic labels to speed differentiation and treatment selection.', 'Shock Management - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Integrated NCLEX triage in this shock scenario?', 'Which finding best supports Integrated NCLEX triage in this shock scenario?', '[{"id": "a", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "b", "text": "This pattern is more consistent with Cardiogenic profile."}, {"id": "c", "text": "Identify compensated shock early and tailor treatment by mechanism."}, {"id": "d", "text": "All shock is treated identically long-term in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Early shock recognition hinges on tachycardia/tachypnea/anxiety before hypotension, with subtype-targeted definitive management thereafter. Identify compensated shock early and tailor treatment by mechanism.', 'Shock Management - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews hemodynamic data. Which interpretation best matches Shock definition?', 'The nurse reviews hemodynamic data. Which interpretation best matches Shock definition?', '[{"id": "a", "text": "Shock is defined as isolated hypertension in this note."}, {"id": "b", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "c", "text": "This pattern is more consistent with Septic profile."}, {"id": "d", "text": "Shock is inadequate tissue perfusion causing insufficient oxygen delivery and cellular dysfunction."}]'::jsonb, '["d"]'::jsonb, 'Correct because Shock is inadequate tissue perfusion causing insufficient oxygen delivery and cellular dysfunction. Treat perfusion failure early to prevent irreversible organ injury.', 'Shock Management - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Shock metabolic pathway?', 'Which clinical judgment is most accurate regarding Shock metabolic pathway?', '[{"id": "a", "text": "Track lactate and organ function to detect decompensation early."}, {"id": "b", "text": "Shock produces alkalosis from hyperperfusion in this note."}, {"id": "c", "text": "This pattern is more consistent with Neurogenic profile."}, {"id": "d", "text": "Blood pressure normalization alone confirms full recovery."}]'::jsonb, '["a"]'::jsonb, 'Correct because In shock, anaerobic metabolism develops with lactic acidosis and can progress to MODS. Track lactate and organ function to detect decompensation early.', 'Shock Management - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Hypovolemic profile?', 'In urgent triage, which conclusion aligns with Hypovolemic profile?', '[{"id": "a", "text": "This pattern is more consistent with Obstructive profile."}, {"id": "b", "text": "Hypovolemic shock stems from blood/fluid loss with low CO, high SVR, flat neck veins, pallor, and tachycardia."}, {"id": "c", "text": "Hypovolemic shock has high CO and low SVR in this note."}, {"id": "d", "text": "Blood pressure normalization alone confirms full recovery."}]'::jsonb, '["b"]'::jsonb, 'Correct because Hypovolemic shock stems from blood/fluid loss with low CO, high SVR, flat neck veins, pallor, and tachycardia. Rapid volume replacement and bleeding control are primary priorities.', 'Shock Management - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Cardiogenic profile?', 'Which statement most appropriately reflects Cardiogenic profile?', '[{"id": "a", "text": "This pattern is more consistent with Early shock signs."}, {"id": "b", "text": "Support contractility and address the primary cardiac lesion urgently."}, {"id": "c", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "d", "text": "Cardiogenic shock presents with flat neck veins in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Cardiogenic shock is pump failure (e.g., MI/HF/cardiomyopathy) with low CO, high SVR, JVD, crackles, S3, and frothy sputum. Support contractility and address the primary cardiac lesion urgently.', 'Shock Management - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Septic profile in this shock scenario?', 'Which finding best supports Septic profile in this shock scenario?', '[{"id": "a", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "b", "text": "This pattern is more consistent with Late shock signs."}, {"id": "c", "text": "Septic shock always has high SVR in this note."}, {"id": "d", "text": "Septic shock is distributive vasodilation with low SVR and warm flushed skin early; CO may be high early then low late."}]'::jsonb, '["d"]'::jsonb, 'Correct because Septic shock is distributive vasodilation with low SVR and warm flushed skin early; CO may be high early then low late. Initiate sepsis bundle quickly before transition to late hypodynamic phase.', 'Shock Management - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews hemodynamic data. Which interpretation best matches Neurogenic profile?', 'The nurse reviews hemodynamic data. Which interpretation best matches Neurogenic profile?', '[{"id": "a", "text": "Neurogenic shock usually causes tachycardia in this note."}, {"id": "b", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "c", "text": "Recognize bradycardia-hypotension pattern as distinguishing feature."}, {"id": "d", "text": "Neurogenic shock has high SVR in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Neurogenic shock follows spinal injury with loss of sympathetic tone causing low CO, low SVR, bradycardia, hypotension, and warm dry skin below injury. Recognize bradycardia-hypotension pattern as distinguishing feature.', 'Shock Management - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Obstructive profile?', 'Which clinical judgment is most accurate regarding Obstructive profile?', '[{"id": "a", "text": "This pattern is more consistent with General initial treatment."}, {"id": "b", "text": "Obstructive shock has high CO in this note."}, {"id": "c", "text": "Obstructive shock is due to physical flow obstruction (tamponade, tension PTX, PE) with low CO and high SVR."}, {"id": "d", "text": "Blood pressure normalization alone confirms full recovery."}]'::jsonb, '["c"]'::jsonb, 'Correct because Obstructive shock is due to physical flow obstruction (tamponade, tension PTX, PE) with low CO and high SVR. Definitive relief of obstruction is mandatory for recovery.', 'Shock Management - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Early shock signs?', 'In urgent triage, which conclusion aligns with Early shock signs?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "Do not be reassured by normal BP when compensatory signs are present."}, {"id": "c", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "d", "text": "Normal BP excludes early shock in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Early compensated shock shows tachycardia first, possible normal BP, cool clammy skin, tachypnea, anxiety, and slight urine decrease. Do not be reassured by normal BP when compensatory signs are present.', 'Shock Management - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Late shock signs?', 'Which statement most appropriately reflects Late shock signs?', '[{"id": "a", "text": "Late shock has improving urine output in this note."}, {"id": "b", "text": "Late decompensated shock includes hypotension, altered LOC, urine output <30 mL/hr, mottled/cyanotic skin, lactic acidosis, and MODS progression."}, {"id": "c", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "d", "text": "Shock subtype is irrelevant once oxygen is started."}]'::jsonb, '["b"]'::jsonb, 'Correct because Late decompensated shock includes hypotension, altered LOC, urine output <30 mL/hr, mottled/cyanotic skin, lactic acidosis, and MODS progression. Escalate aggressively at decompensation to prevent arrest.', 'Shock Management - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports NCLEX early warning in this shock scenario?', 'Which finding best supports NCLEX early warning in this shock scenario?', '[{"id": "a", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "b", "text": "Prioritize trend recognition over single BP value."}, {"id": "c", "text": "Normal BP definitively excludes shock in this note."}, {"id": "d", "text": "Bradycardia is first universal shock sign in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because NCLEX priority notes that tachycardia is first and BP drops last, so normal BP does not rule out shock. Prioritize trend recognition over single BP value.', 'Shock Management - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews hemodynamic data. Which interpretation best matches General initial treatment?', 'The nurse reviews hemodynamic data. Which interpretation best matches General initial treatment?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "This pattern is more consistent with Shock lab panel."}, {"id": "c", "text": "General treatment includes oxygenation, large-bore IV access, continuous monitoring, urine output goals, and broad shock labs."}, {"id": "d", "text": "Monitoring can be delayed until subtype confirmed in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because General treatment includes oxygenation, large-bore IV access, continuous monitoring, urine output goals, and broad shock labs. Rapid stabilization and monitoring should start before definitive subtype treatment.', 'Shock Management - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Positioning rule?', 'Which clinical judgment is most accurate regarding Positioning rule?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "All shock types should use strict Trendelenburg in this note."}, {"id": "c", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "d", "text": "Choose position by shock type to avoid worsening pulmonary congestion."}]'::jsonb, '["d"]'::jsonb, 'Correct because Shock positioning is generally supine with legs elevated (Trendelenburg/modified), except cardiogenic shock where HOB is elevated. Choose position by shock type to avoid worsening pulmonary congestion.', 'Shock Management - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Urine output target?', 'In urgent triage, which conclusion aligns with Urine output target?', '[{"id": "a", "text": "Urine output monitoring is optional in shock in this note."}, {"id": "b", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "c", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "d", "text": "Foley monitoring goal is urine output greater than 0.5 mL/kg/hr."}]'::jsonb, '["d"]'::jsonb, 'Correct because Foley monitoring goal is urine output greater than 0.5 mL/kg/hr. Renal perfusion tracking is critical in shock resuscitation.', 'Shock Management - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Severe shock invasive monitoring?', 'Which statement most appropriately reflects Severe shock invasive monitoring?', '[{"id": "a", "text": "Only pulse oximetry is needed in severe shock in this note."}, {"id": "b", "text": "Invasive lines are contraindicated in severe shock in this note."}, {"id": "c", "text": "Use invasive monitoring when rapid titration is needed."}, {"id": "d", "text": "This pattern is more consistent with Septic bundle timing."}]'::jsonb, '["c"]'::jsonb, 'Correct because Arterial and central lines are used in severe shock for close hemodynamic management. Use invasive monitoring when rapid titration is needed.', 'Shock Management - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Shock lab panel in this shock scenario?', 'Which finding best supports Shock lab panel in this shock scenario?', '[{"id": "a", "text": "Recommended labs include ABG, lactate, CBC, BMP, coagulation tests, and blood cultures in sepsis."}, {"id": "b", "text": "Only lipid panel is urgent in this note."}, {"id": "c", "text": "No labs are needed during shock in this note."}, {"id": "d", "text": "Shock subtype is irrelevant once oxygen is started."}]'::jsonb, '["a"]'::jsonb, 'Correct because Recommended labs include ABG, lactate, CBC, BMP, coagulation tests, and blood cultures in sepsis. Combine perfusion, metabolic, and infectious data quickly.', 'Shock Management - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews hemodynamic data. Which interpretation best matches Hypovolemic treatment specifics?', 'The nurse reviews hemodynamic data. Which interpretation best matches Hypovolemic treatment specifics?', '[{"id": "a", "text": "This pattern is more consistent with Neurogenic treatment specifics."}, {"id": "b", "text": "Restore intravascular volume before vasoconstriction strategies."}, {"id": "c", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "d", "text": "Shock subtype is irrelevant once oxygen is started."}]'::jsonb, '["b"]'::jsonb, 'Correct because Hypovolemic treatment is IV crystalloids (NS/LR), blood products if hemorrhagic, bleeding control, and delaying vasopressors until volume replacement. Restore intravascular volume before vasoconstriction strategies.', 'Shock Management - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Cardiogenic treatment specifics?', 'Which clinical judgment is most accurate regarding Cardiogenic treatment specifics?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "Inotropes are contraindicated in cardiogenic shock in this note."}, {"id": "c", "text": "Cardiogenic management includes treating cause (e.g., PCI for MI), inotropes (dobutamine/milrinone), norepinephrine if persistent hypotension, diuretics if overloaded, and possible IABP/LVAD."}, {"id": "d", "text": "This pattern is more consistent with Obstructive definitive care."}]'::jsonb, '["c"]'::jsonb, 'Correct because Cardiogenic management includes treating cause (e.g., PCI for MI), inotropes (dobutamine/milrinone), norepinephrine if persistent hypotension, diuretics if overloaded, and possible IABP/LVAD. Support pump function while correcting primary cardiac pathology.', 'Shock Management - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Septic bundle timing?', 'In urgent triage, which conclusion aligns with Septic bundle timing?', '[{"id": "a", "text": "Fluid bolus is contraindicated in septic shock in this note."}, {"id": "b", "text": "Time-sensitive sepsis actions strongly influence outcomes."}, {"id": "c", "text": "This pattern is more consistent with Norepinephrine profile."}, {"id": "d", "text": "Antibiotics are delayed until cultures finalize in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Septic shock care includes blood cultures before antibiotics, broad-spectrum antibiotics within 1 hour, and 30 mL/kg fluid bolus within 3 hours. Time-sensitive sepsis actions strongly influence outcomes.', 'Shock Management - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Septic vasopressors/steroids?', 'Which statement most appropriately reflects Septic vasopressors/steroids?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "Dobutamine alone is first-line septic pressor in this note."}, {"id": "c", "text": "Steroids are always first treatment before fluids in this note."}, {"id": "d", "text": "Norepinephrine is first-line vasopressor in septic shock, with corticosteroids considered if refractory."}]'::jsonb, '["d"]'::jsonb, 'Correct because Norepinephrine is first-line vasopressor in septic shock, with corticosteroids considered if refractory. Escalate pressor support and adjuncts when fluid response is inadequate.', 'Shock Management - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Neurogenic treatment specifics in this shock scenario?', 'Which finding best supports Neurogenic treatment specifics in this shock scenario?', '[{"id": "a", "text": "This pattern is more consistent with Epinephrine and vasopressin profiles."}, {"id": "b", "text": "Neurogenic shock requires no vasopressors in this note."}, {"id": "c", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "d", "text": "Address vasodilation and bradycardia while protecting spinal injury."}]'::jsonb, '["d"]'::jsonb, 'Correct because Neurogenic shock treatment includes cautious fluids, norepinephrine/phenylephrine, atropine for bradycardia, and spinal immobilization. Address vasodilation and bradycardia while protecting spinal injury.', 'Shock Management - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews hemodynamic data. Which interpretation best matches Obstructive definitive care?', 'The nurse reviews hemodynamic data. Which interpretation best matches Obstructive definitive care?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "Obstructive shock requires removing obstruction: pericardiocentesis for tamponade, needle decompression for tension PTX, and thrombolysis/embolectomy for PE."}, {"id": "c", "text": "Obstructive shock is corrected by fluids alone in this note."}, {"id": "d", "text": "This pattern is more consistent with Shock-type mnemonic."}]'::jsonb, '["b"]'::jsonb, 'Correct because Obstructive shock requires removing obstruction: pericardiocentesis for tamponade, needle decompression for tension PTX, and thrombolysis/embolectomy for PE. Definitive mechanical relief is essential; supportive measures alone are insufficient.', 'Shock Management - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Norepinephrine profile?', 'Which clinical judgment is most accurate regarding Norepinephrine profile?', '[{"id": "a", "text": "Shock subtype is irrelevant once oxygen is started."}, {"id": "b", "text": "This pattern is more consistent with Integrated NCLEX triage."}, {"id": "c", "text": "Monitor peripheral perfusion while titrating SVR support."}, {"id": "d", "text": "Norepinephrine is pure β2 bronchodilator in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Norepinephrine acts via α1 + β1 to increase SVR with mild CO effect and is first-line for septic shock; also used in neurogenic shock. Monitor peripheral perfusion while titrating SVR support.', 'Shock Management - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Dobutamine profile?', 'In urgent triage, which conclusion aligns with Dobutamine profile?', '[{"id": "a", "text": "Dobutamine is a β1 inotrope increasing contractility and is used in cardiogenic shock with reduced EF."}, {"id": "b", "text": "Dobutamine primarily decreases contractility in this note."}, {"id": "c", "text": "Dobutamine is first-line for anaphylaxis in this note."}, {"id": "d", "text": "Blood pressure normalization alone confirms full recovery."}]'::jsonb, '["a"]'::jsonb, 'Correct because Dobutamine is a β1 inotrope increasing contractility and is used in cardiogenic shock with reduced EF. Use inotropy to augment forward flow in pump failure.', 'Shock Management - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Epinephrine and vasopressin profiles?', 'Which statement most appropriately reflects Epinephrine and vasopressin profiles?', '[{"id": "a", "text": "This pattern is more consistent with Shock metabolic pathway."}, {"id": "b", "text": "Blood pressure normalization alone confirms full recovery."}, {"id": "c", "text": "Match pressor receptor profile to clinical indication."}, {"id": "d", "text": "Epinephrine has no cardiovascular receptor effects in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Epinephrine is α1/β1/β2 and used in anaphylaxis/cardiac arrest, while vasopressin (V1) is septic add-on vasoconstrictor. Match pressor receptor profile to clinical indication.', 'Shock Management - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Shock definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Shock definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Shock reflects inadequate tissue perfusion."}, {"id": "b", "text": "Shock is a physiologic emergency state."}, {"id": "c", "text": "Shock has no effect on oxygen delivery in this note."}, {"id": "d", "text": "Cellular oxygen delivery is insufficient in shock."}, {"id": "e", "text": "Shock is defined as isolated hypertension in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Shock is inadequate tissue perfusion causing insufficient oxygen delivery and cellular dysfunction.', 'Shock Management - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Shock metabolic pathway, which statements are correct? (Select all that apply)', 'For management involving Shock metabolic pathway, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Shock produces alkalosis from hyperperfusion in this note."}, {"id": "b", "text": "Lactic acidosis is a listed consequence."}, {"id": "c", "text": "Shock cannot cause organ dysfunction in this note."}, {"id": "d", "text": "Anaerobic metabolism occurs in shock."}, {"id": "e", "text": "Progression may lead to MODS."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: In shock, anaerobic metabolism develops with lactic acidosis and can progress to MODS.', 'Shock Management - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Hypovolemic profile. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Hypovolemic profile. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Hypovolemic shock has high CO and low SVR in this note."}, {"id": "b", "text": "Flat neck veins are listed key sign."}, {"id": "c", "text": "SVR increases compensatorily in hypovolemic shock."}, {"id": "d", "text": "CO decreases in hypovolemic shock."}, {"id": "e", "text": "JVD is classic hypovolemic finding in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Hypovolemic shock stems from blood/fluid loss with low CO, high SVR, flat neck veins, pallor, and tachycardia.', 'Shock Management - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Cardiogenic profile? (Select all that apply)', 'During reassessment, which observations support Cardiogenic profile? (Select all that apply)', '[{"id": "a", "text": "S3/frothy sputum are associated findings."}, {"id": "b", "text": "Cardiogenic shock has elevated CO in this note."}, {"id": "c", "text": "Pump failure etiology is listed for cardiogenic shock."}, {"id": "d", "text": "JVD and crackles are key signs."}, {"id": "e", "text": "Cardiogenic shock presents with flat neck veins in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Cardiogenic shock is pump failure (e.g., MI/HF/cardiomyopathy) with low CO, high SVR, JVD, crackles, S3, and frothy sputum.', 'Shock Management - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Septic profile in this note? (Select all that apply)', 'Which cues are consistent with Septic profile in this note? (Select all that apply)', '[{"id": "a", "text": "Skin is cold/clammy from onset in all septic phases in this note."}, {"id": "b", "text": "Septic shock always has high SVR in this note."}, {"id": "c", "text": "Septic shock is distributive with vasodilation."}, {"id": "d", "text": "SVR is reduced in septic shock."}, {"id": "e", "text": "CO may be high early and low late."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Septic shock is distributive vasodilation with low SVR and warm flushed skin early; CO may be high early then low late.', 'Shock Management - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Neurogenic profile. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Neurogenic profile. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Loss of sympathetic tone is mechanism."}, {"id": "b", "text": "Neurogenic shock usually causes tachycardia in this note."}, {"id": "c", "text": "Warm dry skin below injury is listed."}, {"id": "d", "text": "Neurogenic shock includes bradycardia and hypotension."}, {"id": "e", "text": "Neurogenic shock has high SVR in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Neurogenic shock follows spinal injury with loss of sympathetic tone causing low CO, low SVR, bradycardia, hypotension, and warm dry skin below injury.', 'Shock Management - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Obstructive profile, which statements are correct? (Select all that apply)', 'For management involving Obstructive profile, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Obstructive shock is caused by volume loss only in this note."}, {"id": "b", "text": "Obstructive shock has high CO in this note."}, {"id": "c", "text": "SVR is increased in obstructive shock."}, {"id": "d", "text": "Tamponade/tension PTX/PE are listed causes."}, {"id": "e", "text": "CO is reduced in obstructive shock."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Obstructive shock is due to physical flow obstruction (tamponade, tension PTX, PE) with low CO and high SVR.', 'Shock Management - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Early shock signs. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Early shock signs. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Normal BP excludes early shock in this note."}, {"id": "b", "text": "Cool clammy skin and tachypnea are early signs."}, {"id": "c", "text": "BP may still be normal early."}, {"id": "d", "text": "Hypotension is first sign of shock in this note."}, {"id": "e", "text": "Tachycardia is first compensatory sign."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Early compensated shock shows tachycardia first, possible normal BP, cool clammy skin, tachypnea, anxiety, and slight urine decrease.', 'Shock Management - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Late shock signs? (Select all that apply)', 'During reassessment, which observations support Late shock signs? (Select all that apply)', '[{"id": "a", "text": "Urine output under 30 mL/hr is late sign."}, {"id": "b", "text": "Mottling/cyanosis and acidosis indicate decompensation."}, {"id": "c", "text": "Late shock has improving urine output in this note."}, {"id": "d", "text": "Late shock preserves normal mentation in this note."}, {"id": "e", "text": "Hypotension appears in late shock."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Late decompensated shock includes hypotension, altered LOC, urine output <30 mL/hr, mottled/cyanotic skin, lactic acidosis, and MODS progression.', 'Shock Management - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with NCLEX early warning in this note? (Select all that apply)', 'Which cues are consistent with NCLEX early warning in this note? (Select all that apply)', '[{"id": "a", "text": "Tachycardia-first principle is emphasized."}, {"id": "b", "text": "BP drop is late finding."}, {"id": "c", "text": "Normal BP cannot exclude early shock."}, {"id": "d", "text": "Normal BP definitively excludes shock in this note."}, {"id": "e", "text": "Bradycardia is first universal shock sign in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: NCLEX priority notes that tachycardia is first and BP drops last, so normal BP does not rule out shock.', 'Shock Management - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for General initial treatment. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for General initial treatment. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Two large-bore IVs are recommended."}, {"id": "b", "text": "Shock treatment begins with oral fluids only in this note."}, {"id": "c", "text": "High-flow oxygen is listed in initial management."}, {"id": "d", "text": "Monitoring can be delayed until subtype confirmed in this note."}, {"id": "e", "text": "Continuous vitals/SpO2/urine monitoring is required."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: General treatment includes oxygenation, large-bore IV access, continuous monitoring, urine output goals, and broad shock labs.', 'Shock Management - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Positioning rule, which statements are correct? (Select all that apply)', 'For management involving Positioning rule, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Positioning differs by hemodynamic context."}, {"id": "b", "text": "Cardiogenic shock requires leg elevation above heart in this note."}, {"id": "c", "text": "Cardiogenic shock is exception with HOB elevation."}, {"id": "d", "text": "All shock types should use strict Trendelenburg in this note."}, {"id": "e", "text": "Leg-elevated supine is general shock position."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Shock positioning is generally supine with legs elevated (Trendelenburg/modified), except cardiogenic shock where HOB is elevated.', 'Shock Management - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Urine output target. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Urine output target. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Goal >0.5 mL/kg/hr is listed."}, {"id": "b", "text": "Low output suggests perfusion compromise."}, {"id": "c", "text": "Urine output monitoring is optional in shock in this note."}, {"id": "d", "text": "Foley is recommended for hourly urine monitoring."}, {"id": "e", "text": "Goal urine output is 0.05 mL/kg/hr in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Foley monitoring goal is urine output greater than 0.5 mL/kg/hr.', 'Shock Management - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Severe shock invasive monitoring? (Select all that apply)', 'During reassessment, which observations support Severe shock invasive monitoring? (Select all that apply)', '[{"id": "a", "text": "Invasive monitoring supports advanced management."}, {"id": "b", "text": "Arterial line is listed in severe shock."}, {"id": "c", "text": "Only pulse oximetry is needed in severe shock in this note."}, {"id": "d", "text": "Central line is listed in severe shock."}, {"id": "e", "text": "Invasive lines are contraindicated in severe shock in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Arterial and central lines are used in severe shock for close hemodynamic management.', 'Shock Management - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Shock lab panel in this note? (Select all that apply)', 'Which cues are consistent with Shock lab panel in this note? (Select all that apply)', '[{"id": "a", "text": "No labs are needed during shock in this note."}, {"id": "b", "text": "ABG and lactate are listed labs."}, {"id": "c", "text": "Blood cultures are included for sepsis context."}, {"id": "d", "text": "CBC/BMP/coags are listed labs."}, {"id": "e", "text": "Only lipid panel is urgent in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Recommended labs include ABG, lactate, CBC, BMP, coagulation tests, and blood cultures in sepsis.', 'Shock Management - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Hypovolemic treatment specifics. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Hypovolemic treatment specifics. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Vasopressors are first-line before fluids in hypovolemia in this note."}, {"id": "b", "text": "PRBC/FFP used in hemorrhagic shock."}, {"id": "c", "text": "Bleeding source control is unnecessary in this note."}, {"id": "d", "text": "No vasopressors before adequate volume is key point."}, {"id": "e", "text": "NS/LR fluid resuscitation is listed."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Hypovolemic treatment is IV crystalloids (NS/LR), blood products if hemorrhagic, bleeding control, and delaying vasopressors until volume replacement.', 'Shock Management - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Cardiogenic treatment specifics, which statements are correct? (Select all that apply)', 'For management involving Cardiogenic treatment specifics, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Cardiogenic shock is treated with volume loading only in this note."}, {"id": "b", "text": "Inotropes are contraindicated in cardiogenic shock in this note."}, {"id": "c", "text": "Dobutamine/milrinone are listed inotropes."}, {"id": "d", "text": "IABP/LVAD are listed for refractory cases."}, {"id": "e", "text": "Norepinephrine may be added if hypotension persists."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Cardiogenic management includes treating cause (e.g., PCI for MI), inotropes (dobutamine/milrinone), norepinephrine if persistent hypotension, diuretics if overloaded, and possible IABP/LVAD.', 'Shock Management - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Septic bundle timing. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Septic bundle timing. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Antibiotics are given within one hour."}, {"id": "b", "text": "30 mL/kg bolus within 3 hours is listed."}, {"id": "c", "text": "Fluid bolus is contraindicated in septic shock in this note."}, {"id": "d", "text": "Cultures are obtained before antibiotics."}, {"id": "e", "text": "Antibiotics are delayed until cultures finalize in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Septic shock care includes blood cultures before antibiotics, broad-spectrum antibiotics within 1 hour, and 30 mL/kg fluid bolus within 3 hours.', 'Shock Management - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Septic vasopressors/steroids? (Select all that apply)', 'During reassessment, which observations support Septic vasopressors/steroids? (Select all that apply)', '[{"id": "a", "text": "Steroids are always first treatment before fluids in this note."}, {"id": "b", "text": "Norepinephrine first-line is explicitly listed."}, {"id": "c", "text": "Steroids are considered in refractory septic shock."}, {"id": "d", "text": "Dobutamine alone is first-line septic pressor in this note."}, {"id": "e", "text": "Septic vasodilatory physiology supports pressor use."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Norepinephrine is first-line vasopressor in septic shock, with corticosteroids considered if refractory.', 'Shock Management - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Neurogenic treatment specifics in this note? (Select all that apply)', 'Which cues are consistent with Neurogenic treatment specifics in this note? (Select all that apply)', '[{"id": "a", "text": "Neurogenic shock requires no vasopressors in this note."}, {"id": "b", "text": "Spinal immobilization is listed intervention."}, {"id": "c", "text": "Norepinephrine/phenylephrine are listed pressors."}, {"id": "d", "text": "Tachycardia treatment is atropine goal in this note."}, {"id": "e", "text": "Atropine for bradycardia is listed."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Neurogenic shock treatment includes cautious fluids, norepinephrine/phenylephrine, atropine for bradycardia, and spinal immobilization.', 'Shock Management - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Obstructive definitive care. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Obstructive definitive care. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Pericardiocentesis is contraindicated in tamponade in this note."}, {"id": "b", "text": "Obstructive shock is corrected by fluids alone in this note."}, {"id": "c", "text": "PE may need thrombolytics or embolectomy."}, {"id": "d", "text": "Tension PTX needs needle decompression at 2nd ICS MCL."}, {"id": "e", "text": "Tamponade requires pericardiocentesis."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Obstructive shock requires removing obstruction: pericardiocentesis for tamponade, needle decompression for tension PTX, and thrombolysis/embolectomy for PE.', 'Shock Management - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Norepinephrine profile, which statements are correct? (Select all that apply)', 'For management involving Norepinephrine profile, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Norepinephrine is pure β2 bronchodilator in this note."}, {"id": "b", "text": "Norepinephrine lowers SVR in this note."}, {"id": "c", "text": "Neurogenic use is listed."}, {"id": "d", "text": "α1 + β1 mechanism is listed."}, {"id": "e", "text": "First-line in septic shock is listed."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Norepinephrine acts via α1 + β1 to increase SVR with mild CO effect and is first-line for septic shock; also used in neurogenic shock.', 'Shock Management - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Dobutamine profile. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Dobutamine profile. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Used for cardiogenic shock with low EF."}, {"id": "b", "text": "Dobutamine is first-line for anaphylaxis in this note."}, {"id": "c", "text": "Dobutamine is β1 inotrope in note."}, {"id": "d", "text": "Dobutamine primarily decreases contractility in this note."}, {"id": "e", "text": "It increases contractility."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Dobutamine is a β1 inotrope increasing contractility and is used in cardiogenic shock with reduced EF.', 'Shock Management - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Epinephrine and vasopressin profiles? (Select all that apply)', 'During reassessment, which observations support Epinephrine and vasopressin profiles? (Select all that apply)', '[{"id": "a", "text": "Vasopressin is septic add-on via V1 vasoconstriction."}, {"id": "b", "text": "Epinephrine indications include anaphylaxis/cardiac arrest."}, {"id": "c", "text": "Epinephrine has alpha/beta effects in note."}, {"id": "d", "text": "Epinephrine has no cardiovascular receptor effects in this note."}, {"id": "e", "text": "Vasopressin is first-line bronchodilator in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Epinephrine is α1/β1/β2 and used in anaphylaxis/cardiac arrest, while vasopressin (V1) is septic add-on vasoconstrictor.', 'Shock Management - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Shock-type mnemonic in this note? (Select all that apply)', 'Which cues are consistent with Shock-type mnemonic in this note? (Select all that apply)', '[{"id": "a", "text": "Distributive is blocked exit in this note."}, {"id": "b", "text": "Cardiogenic is leaky pipes in this note."}, {"id": "c", "text": "Cardiogenic is broken pump."}, {"id": "d", "text": "Hypovolemic is described as empty tank."}, {"id": "e", "text": "Obstructive is blocked exit."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Mnemonic in note: H hypovolemic (empty tank), C cardiogenic (broken pump), D distributive (leaky pipes), O obstructive (blocked exit).', 'Shock Management - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Integrated NCLEX triage. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Integrated NCLEX triage. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Compensated shock can present before BP drop."}, {"id": "b", "text": "Delayed recognition increases MODS risk."}, {"id": "c", "text": "All shock is treated identically long-term in this note."}, {"id": "d", "text": "Hypotension must appear before any intervention in this note."}, {"id": "e", "text": "Subtype-specific therapy is required after initial stabilization."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Early shock recognition hinges on tachycardia/tachypnea/anxiety before hypotension, with subtype-targeted definitive management thereafter.', 'Shock Management - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Shock definition, which statements are correct? (Select all that apply)', 'For management involving Shock definition, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Shock has no effect on oxygen delivery in this note."}, {"id": "b", "text": "Cellular oxygen delivery is insufficient in shock."}, {"id": "c", "text": "Shock is defined as isolated hypertension in this note."}, {"id": "d", "text": "Shock reflects inadequate tissue perfusion."}, {"id": "e", "text": "Shock is a physiologic emergency state."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Shock is inadequate tissue perfusion causing insufficient oxygen delivery and cellular dysfunction.', 'Shock Management - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Shock metabolic pathway. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Shock metabolic pathway. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Shock produces alkalosis from hyperperfusion in this note."}, {"id": "b", "text": "Shock cannot cause organ dysfunction in this note."}, {"id": "c", "text": "Progression may lead to MODS."}, {"id": "d", "text": "Lactic acidosis is a listed consequence."}, {"id": "e", "text": "Anaerobic metabolism occurs in shock."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: In shock, anaerobic metabolism develops with lactic acidosis and can progress to MODS.', 'Shock Management - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Hypovolemic profile? (Select all that apply)', 'During reassessment, which observations support Hypovolemic profile? (Select all that apply)', '[{"id": "a", "text": "Hypovolemic shock has high CO and low SVR in this note."}, {"id": "b", "text": "SVR increases compensatorily in hypovolemic shock."}, {"id": "c", "text": "JVD is classic hypovolemic finding in this note."}, {"id": "d", "text": "CO decreases in hypovolemic shock."}, {"id": "e", "text": "Flat neck veins are listed key sign."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Hypovolemic shock stems from blood/fluid loss with low CO, high SVR, flat neck veins, pallor, and tachycardia.', 'Shock Management - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Cardiogenic profile in this note? (Select all that apply)', 'Which cues are consistent with Cardiogenic profile in this note? (Select all that apply)', '[{"id": "a", "text": "JVD and crackles are key signs."}, {"id": "b", "text": "Pump failure etiology is listed for cardiogenic shock."}, {"id": "c", "text": "Cardiogenic shock has elevated CO in this note."}, {"id": "d", "text": "Cardiogenic shock presents with flat neck veins in this note."}, {"id": "e", "text": "S3/frothy sputum are associated findings."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Cardiogenic shock is pump failure (e.g., MI/HF/cardiomyopathy) with low CO, high SVR, JVD, crackles, S3, and frothy sputum.', 'Shock Management - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Septic profile. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Septic profile. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "CO may be high early and low late."}, {"id": "b", "text": "Septic shock always has high SVR in this note."}, {"id": "c", "text": "Skin is cold/clammy from onset in all septic phases in this note."}, {"id": "d", "text": "Septic shock is distributive with vasodilation."}, {"id": "e", "text": "SVR is reduced in septic shock."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Septic shock is distributive vasodilation with low SVR and warm flushed skin early; CO may be high early then low late.', 'Shock Management - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Neurogenic profile, which statements are correct? (Select all that apply)', 'For management involving Neurogenic profile, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Neurogenic shock has high SVR in this note."}, {"id": "b", "text": "Neurogenic shock includes bradycardia and hypotension."}, {"id": "c", "text": "Loss of sympathetic tone is mechanism."}, {"id": "d", "text": "Warm dry skin below injury is listed."}, {"id": "e", "text": "Neurogenic shock usually causes tachycardia in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Neurogenic shock follows spinal injury with loss of sympathetic tone causing low CO, low SVR, bradycardia, hypotension, and warm dry skin below injury.', 'Shock Management - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Obstructive profile. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Obstructive profile. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "SVR is increased in obstructive shock."}, {"id": "b", "text": "Obstructive shock has high CO in this note."}, {"id": "c", "text": "Tamponade/tension PTX/PE are listed causes."}, {"id": "d", "text": "Obstructive shock is caused by volume loss only in this note."}, {"id": "e", "text": "CO is reduced in obstructive shock."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Obstructive shock is due to physical flow obstruction (tamponade, tension PTX, PE) with low CO and high SVR.', 'Shock Management - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Early shock signs? (Select all that apply)', 'During reassessment, which observations support Early shock signs? (Select all that apply)', '[{"id": "a", "text": "Tachycardia is first compensatory sign."}, {"id": "b", "text": "Normal BP excludes early shock in this note."}, {"id": "c", "text": "BP may still be normal early."}, {"id": "d", "text": "Hypotension is first sign of shock in this note."}, {"id": "e", "text": "Cool clammy skin and tachypnea are early signs."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Early compensated shock shows tachycardia first, possible normal BP, cool clammy skin, tachypnea, anxiety, and slight urine decrease.', 'Shock Management - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Late shock signs in this note? (Select all that apply)', 'Which cues are consistent with Late shock signs in this note? (Select all that apply)', '[{"id": "a", "text": "Late shock preserves normal mentation in this note."}, {"id": "b", "text": "Urine output under 30 mL/hr is late sign."}, {"id": "c", "text": "Late shock has improving urine output in this note."}, {"id": "d", "text": "Mottling/cyanosis and acidosis indicate decompensation."}, {"id": "e", "text": "Hypotension appears in late shock."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Late decompensated shock includes hypotension, altered LOC, urine output <30 mL/hr, mottled/cyanotic skin, lactic acidosis, and MODS progression.', 'Shock Management - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for NCLEX early warning. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for NCLEX early warning. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "BP drop is late finding."}, {"id": "b", "text": "Bradycardia is first universal shock sign in this note."}, {"id": "c", "text": "Normal BP cannot exclude early shock."}, {"id": "d", "text": "Tachycardia-first principle is emphasized."}, {"id": "e", "text": "Normal BP definitively excludes shock in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: NCLEX priority notes that tachycardia is first and BP drops last, so normal BP does not rule out shock.', 'Shock Management - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving General initial treatment, which statements are correct? (Select all that apply)', 'For management involving General initial treatment, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Two large-bore IVs are recommended."}, {"id": "b", "text": "High-flow oxygen is listed in initial management."}, {"id": "c", "text": "Monitoring can be delayed until subtype confirmed in this note."}, {"id": "d", "text": "Continuous vitals/SpO2/urine monitoring is required."}, {"id": "e", "text": "Shock treatment begins with oral fluids only in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: General treatment includes oxygenation, large-bore IV access, continuous monitoring, urine output goals, and broad shock labs.', 'Shock Management - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Positioning rule. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Positioning rule. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "All shock types should use strict Trendelenburg in this note."}, {"id": "b", "text": "Positioning differs by hemodynamic context."}, {"id": "c", "text": "Cardiogenic shock is exception with HOB elevation."}, {"id": "d", "text": "Cardiogenic shock requires leg elevation above heart in this note."}, {"id": "e", "text": "Leg-elevated supine is general shock position."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Shock positioning is generally supine with legs elevated (Trendelenburg/modified), except cardiogenic shock where HOB is elevated.', 'Shock Management - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Urine output target? (Select all that apply)', 'During reassessment, which observations support Urine output target? (Select all that apply)', '[{"id": "a", "text": "Urine output monitoring is optional in shock in this note."}, {"id": "b", "text": "Goal >0.5 mL/kg/hr is listed."}, {"id": "c", "text": "Low output suggests perfusion compromise."}, {"id": "d", "text": "Foley is recommended for hourly urine monitoring."}, {"id": "e", "text": "Goal urine output is 0.05 mL/kg/hr in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Foley monitoring goal is urine output greater than 0.5 mL/kg/hr.', 'Shock Management - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Severe shock invasive monitoring in this note? (Select all that apply)', 'Which cues are consistent with Severe shock invasive monitoring in this note? (Select all that apply)', '[{"id": "a", "text": "Arterial line is listed in severe shock."}, {"id": "b", "text": "Central line is listed in severe shock."}, {"id": "c", "text": "Invasive lines are contraindicated in severe shock in this note."}, {"id": "d", "text": "Only pulse oximetry is needed in severe shock in this note."}, {"id": "e", "text": "Invasive monitoring supports advanced management."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Arterial and central lines are used in severe shock for close hemodynamic management.', 'Shock Management - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Shock lab panel. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Shock lab panel. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "CBC/BMP/coags are listed labs."}, {"id": "b", "text": "Only lipid panel is urgent in this note."}, {"id": "c", "text": "No labs are needed during shock in this note."}, {"id": "d", "text": "Blood cultures are included for sepsis context."}, {"id": "e", "text": "ABG and lactate are listed labs."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Recommended labs include ABG, lactate, CBC, BMP, coagulation tests, and blood cultures in sepsis.', 'Shock Management - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Hypovolemic treatment specifics, which statements are correct? (Select all that apply)', 'For management involving Hypovolemic treatment specifics, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Bleeding source control is unnecessary in this note."}, {"id": "b", "text": "No vasopressors before adequate volume is key point."}, {"id": "c", "text": "NS/LR fluid resuscitation is listed."}, {"id": "d", "text": "Vasopressors are first-line before fluids in hypovolemia in this note."}, {"id": "e", "text": "PRBC/FFP used in hemorrhagic shock."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Hypovolemic treatment is IV crystalloids (NS/LR), blood products if hemorrhagic, bleeding control, and delaying vasopressors until volume replacement.', 'Shock Management - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Cardiogenic treatment specifics. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Cardiogenic treatment specifics. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Cardiogenic shock is treated with volume loading only in this note."}, {"id": "b", "text": "Norepinephrine may be added if hypotension persists."}, {"id": "c", "text": "Inotropes are contraindicated in cardiogenic shock in this note."}, {"id": "d", "text": "Dobutamine/milrinone are listed inotropes."}, {"id": "e", "text": "IABP/LVAD are listed for refractory cases."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Cardiogenic management includes treating cause (e.g., PCI for MI), inotropes (dobutamine/milrinone), norepinephrine if persistent hypotension, diuretics if overloaded, and possible IABP/LVAD.', 'Shock Management - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Septic bundle timing? (Select all that apply)', 'During reassessment, which observations support Septic bundle timing? (Select all that apply)', '[{"id": "a", "text": "Antibiotics are delayed until cultures finalize in this note."}, {"id": "b", "text": "Antibiotics are given within one hour."}, {"id": "c", "text": "30 mL/kg bolus within 3 hours is listed."}, {"id": "d", "text": "Fluid bolus is contraindicated in septic shock in this note."}, {"id": "e", "text": "Cultures are obtained before antibiotics."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Septic shock care includes blood cultures before antibiotics, broad-spectrum antibiotics within 1 hour, and 30 mL/kg fluid bolus within 3 hours.', 'Shock Management - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Septic vasopressors/steroids in this note? (Select all that apply)', 'Which cues are consistent with Septic vasopressors/steroids in this note? (Select all that apply)', '[{"id": "a", "text": "Steroids are considered in refractory septic shock."}, {"id": "b", "text": "Dobutamine alone is first-line septic pressor in this note."}, {"id": "c", "text": "Norepinephrine first-line is explicitly listed."}, {"id": "d", "text": "Steroids are always first treatment before fluids in this note."}, {"id": "e", "text": "Septic vasodilatory physiology supports pressor use."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Norepinephrine is first-line vasopressor in septic shock, with corticosteroids considered if refractory.', 'Shock Management - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Neurogenic treatment specifics. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Neurogenic treatment specifics. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Neurogenic shock requires no vasopressors in this note."}, {"id": "b", "text": "Tachycardia treatment is atropine goal in this note."}, {"id": "c", "text": "Spinal immobilization is listed intervention."}, {"id": "d", "text": "Atropine for bradycardia is listed."}, {"id": "e", "text": "Norepinephrine/phenylephrine are listed pressors."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Neurogenic shock treatment includes cautious fluids, norepinephrine/phenylephrine, atropine for bradycardia, and spinal immobilization.', 'Shock Management - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Obstructive definitive care, which statements are correct? (Select all that apply)', 'For management involving Obstructive definitive care, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Tension PTX needs needle decompression at 2nd ICS MCL."}, {"id": "b", "text": "Tamponade requires pericardiocentesis."}, {"id": "c", "text": "Obstructive shock is corrected by fluids alone in this note."}, {"id": "d", "text": "PE may need thrombolytics or embolectomy."}, {"id": "e", "text": "Pericardiocentesis is contraindicated in tamponade in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Obstructive shock requires removing obstruction: pericardiocentesis for tamponade, needle decompression for tension PTX, and thrombolysis/embolectomy for PE.', 'Shock Management - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Norepinephrine profile. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Norepinephrine profile. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "First-line in septic shock is listed."}, {"id": "b", "text": "α1 + β1 mechanism is listed."}, {"id": "c", "text": "Norepinephrine is pure β2 bronchodilator in this note."}, {"id": "d", "text": "Norepinephrine lowers SVR in this note."}, {"id": "e", "text": "Neurogenic use is listed."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Norepinephrine acts via α1 + β1 to increase SVR with mild CO effect and is first-line for septic shock; also used in neurogenic shock.', 'Shock Management - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Dobutamine profile? (Select all that apply)', 'During reassessment, which observations support Dobutamine profile? (Select all that apply)', '[{"id": "a", "text": "Dobutamine primarily decreases contractility in this note."}, {"id": "b", "text": "Dobutamine is first-line for anaphylaxis in this note."}, {"id": "c", "text": "Used for cardiogenic shock with low EF."}, {"id": "d", "text": "It increases contractility."}, {"id": "e", "text": "Dobutamine is β1 inotrope in note."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Dobutamine is a β1 inotrope increasing contractility and is used in cardiogenic shock with reduced EF.', 'Shock Management - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Epinephrine and vasopressin profiles in this note? (Select all that apply)', 'Which cues are consistent with Epinephrine and vasopressin profiles in this note? (Select all that apply)', '[{"id": "a", "text": "Vasopressin is septic add-on via V1 vasoconstriction."}, {"id": "b", "text": "Epinephrine has alpha/beta effects in note."}, {"id": "c", "text": "Vasopressin is first-line bronchodilator in this note."}, {"id": "d", "text": "Epinephrine has no cardiovascular receptor effects in this note."}, {"id": "e", "text": "Epinephrine indications include anaphylaxis/cardiac arrest."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Epinephrine is α1/β1/β2 and used in anaphylaxis/cardiac arrest, while vasopressin (V1) is septic add-on vasoconstrictor.', 'Shock Management - NCLEX', true, 100, 1, true);
END $$;
